create table public.subscription_plans (id uuid primary key default gen_random_uuid(), name text unique not null, monthly_price numeric(12,2) not null, yearly_price numeric(12,2) not null, features jsonb not null default '[]', limits jsonb not null default '{}');
create table public.subscriptions (id uuid primary key default gen_random_uuid(), business_id uuid not null references public.businesses(id) on delete cascade, plan_id uuid not null references public.subscription_plans(id), start_date date not null, renewal_date date not null, billing_cycle text not null check (billing_cycle in ('monthly','yearly')), status text not null check (status in ('Active','Trial','Expired','Suspended','Cancelled')), auto_renew boolean not null default true, created_at timestamptz not null default now());
create table public.invoices (id uuid primary key default gen_random_uuid(), business_id uuid not null references public.businesses(id) on delete cascade, subscription_id uuid references public.subscriptions(id) on delete set null, invoice_number text unique not null, plan_name text not null, subtotal numeric(12,2) not null, gst_amount numeric(12,2) not null, amount numeric(12,2) not null, currency text not null default 'INR', due_date date not null, paid_date date, status text not null check (status in ('Pending','Paid','Overdue','Cancelled')), created_at timestamptz not null default now());
create table public.payments (id uuid primary key default gen_random_uuid(), business_id uuid not null references public.businesses(id) on delete cascade, invoice_id uuid not null references public.invoices(id) on delete cascade, transaction_id text unique not null, amount numeric(12,2) not null, currency text not null, method text not null, provider text not null default 'razorpay', status text not null check (status in ('Success','Failed','Pending','Refunded')), created_at timestamptz not null default now());
create table public.billing_notifications (id uuid primary key default gen_random_uuid(), business_id uuid not null references public.businesses(id) on delete cascade, type text not null, message text not null, read_at timestamptz, created_at timestamptz not null default now());
insert into public.subscription_plans (name, monthly_price, yearly_price, features, limits) values ('Free',0,0,'["1 website","Basic support"]','{"websites":1}'),('Starter',1499,14990,'["1 website","Domain management"]','{"websites":1}'),('Professional',3999,39990,'["3 websites","Analytics","Priority support"]','{"websites":3}'),('Premium',7999,79990,'["10 websites","Advanced support"]','{"websites":10}'),('Enterprise',19999,199990,'["Unlimited websites","Dedicated support"]','{"websites":999}') on conflict (name) do nothing;
alter table public.subscription_plans enable row level security; alter table public.subscriptions enable row level security; alter table public.invoices enable row level security; alter table public.payments enable row level security; alter table public.billing_notifications enable row level security;
create policy "Authenticated users can view plans" on public.subscription_plans for select to authenticated using (true);
create policy "Owners manage subscriptions" on public.subscriptions for all using (exists (select 1 from public.businesses where businesses.id=subscriptions.business_id and businesses.owner_id=auth.uid())) with check (exists (select 1 from public.businesses where businesses.id=subscriptions.business_id and businesses.owner_id=auth.uid()));
create policy "Owners manage invoices" on public.invoices for all using (exists (select 1 from public.businesses where businesses.id=invoices.business_id and businesses.owner_id=auth.uid())) with check (exists (select 1 from public.businesses where businesses.id=invoices.business_id and businesses.owner_id=auth.uid()));
create policy "Owners manage payments" on public.payments for all using (exists (select 1 from public.businesses where businesses.id=payments.business_id and businesses.owner_id=auth.uid())) with check (exists (select 1 from public.businesses where businesses.id=payments.business_id and businesses.owner_id=auth.uid()));
create policy "Owners view billing notifications" on public.billing_notifications for select using (exists (select 1 from public.businesses where businesses.id=billing_notifications.business_id and businesses.owner_id=auth.uid()));
create policy "Owners create billing notifications" on public.billing_notifications for insert with check (exists (select 1 from public.businesses where businesses.id=billing_notifications.business_id and businesses.owner_id=auth.uid()));
